import React, { useState, useEffect } from 'react';

function AvatarPreview({ user, measurements, outfit, onBack }) {
  const [profile, setProfile] = useState(null);
  const [avatarUrl, setAvatarUrl] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await fetch(`http://localhost:3000/api/users/${user.id}/profile`);
      const data = await response.json();
      setProfile(data);
      generateAvatarUrl(data);
    } catch (error) {
      console.error('Error fetching profile:', error);
      generateAvatarUrl(null);
    } finally {
      setLoading(false);
    }
  };

  const generateAvatarUrl = (profileData) => {
    // Generate a unique seed based on user ID for consistency
    const seed = `${user.id}-${profileData?.profile?.skinTone || 'medium'}-${profileData?.profile?.bodyType || 'average'}`;

    // Using DiceBear API - free service for realistic avatars
    // Style: "personas" for realistic human-like avatars
    const url = `https://api.dicebear.com/7.x/personas/svg?seed=${encodeURIComponent(seed)}&scale=90&backgroundColor=f5f5f5`;

    setAvatarUrl(url);
  };

  if (loading) return <div className="App"><div className="card"><p>Loading your avatar...</p></div></div>;

  return (
    <div className="App avatar-preview">
      <div className="navbar">
        <h1>👤 Your Avatar</h1>
        <button onClick={onBack} className="back-btn">← Back</button>
      </div>
      <div className="avatar-container">
        <div className="avatar-display" style={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          padding: '40px',
          backgroundColor: '#f5f5f5',
          borderRadius: '20px',
          minHeight: '500px'
        }}>
          {avatarUrl && (
            <img 
              src={avatarUrl} 
              alt="Your Avatar" 
              style={{
                maxWidth: '100%',
                maxHeight: '100%',
                width: '400px',
                height: '400px'
              }}
            />
          )}
        </div>
        <div className="avatar-info">
          <h2>Your Profile</h2>
          {profile && (
            <div className="info-box">
              <p><strong>Body Type:</strong> {profile.profile?.bodyType || 'Not set'}</p>
              <p><strong>Skin Tone:</strong> {profile.profile?.skinTone || 'Not set'}</p>
              <p><strong>Style:</strong> {profile.profile?.style || 'Not set'}</p>
              <hr style={{margin: '15px 0', border: 'none', borderTop: '1px solid #ddd'}} />
              <p><strong>Chest:</strong> {profile.measurements?.chest || 'Not set'}"</p>
              <p><strong>Waist:</strong> {profile.measurements?.waist || 'Not set'}"</p>
              <p><strong>Hips:</strong> {profile.measurements?.hips || 'Not set'}"</p>
              <p><strong>Height:</strong> {profile.measurements?.height || 'Not set'}'</p>
            </div>
          )}
          <button onClick={onBack} className="btn-primary" style={{width: '100%', marginTop: '20px'}}>← Back</button>
        </div>
      </div>
    </div>
  );
}

export default AvatarPreview;
